#include <bits/stdc++.h>
using namespace std;
int n,m,dp[102][10004],a[102];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    dp[0][0]=1;
    for(int i=1;i<=n;i++)
        for(int j=0;j<=m;j++)
            if(a[i]<=j)
                dp[i][j]=dp[i-1][j]+dp[i-1][j-a[i]];
            else
                dp[i][j]=dp[i-1][j];
    printf("%d",dp[n][m]);
    return 0;
}
